const express = require('express');
const jwt = require('jsonwebtoken');
const jwksClient = require('jwks-rsa');

const app = express();
const port = 3000;

const client = jwksClient({
  jwksUri: 'https://YOUR_AUTH_SERVER/.well-known/jwks.json'
});

function getKey(header, callback){
  client.getSigningKey(header.kid, function(err, key) {
    const signingKey = key.publicKey || key.rsaPublicKey;
    callback(null, signingKey);
  });
}

function verifyToken(token, callback) {
  jwt.verify(token, getKey, { algorithms: ['RS256'] }, function(err, decoded) {
    if (err) {
      callback(false);
    } else {
      callback(true, decoded);
    }
  });
}

function authenticate(req, res, next) {
  const authHeader = req.headers['authorization'];
  if (!authHeader) return res.sendStatus(401);
  
  const token = authHeader.split(' ')[1];
  verifyToken(token, (isValid, decoded) => {
    if (!isValid) {
      return res.sendStatus(403);
    }
    req.user = decoded;
    next();
  });
}

app.use(authenticate);

app.get('/secure-endpoint', (req, res) => {
  res.json({ message: "You have accessed a secure endpoint!", user: req.user });
});

app.listen(port, () => {
  console.log(`Resource server running at http://localhost:${port}/`);
});